     5→//! VOK Main - Voce Viva Rust binary entry point
     6→//!
     7→//! Provides core VOK commands and delegates kit commands via external subcommand pattern.
     8→//! JJK commands (jjx_*) are handled entirely by the jjk crate when the feature is enabled.
     9→
    10→use clap::Parser;
    11→use std::ffi::OsString;
    12→use std::path::PathBuf;
    13→use std::process::ExitCode;
    14→
    15→#[derive(Parser)]
    16→#[command(name = "vvr")]
    17→#[command(version)]
    18→#[command(about = "Voce Viva Rust - Platform utilities for Claude Code kits")]
    19→#[command(allow_external_subcommands = true)]
    20→struct Cli {
    21→    #[command(subcommand)]
    22→    command: Option<Commands>,
    23→}
    24→
    25→#[derive(clap::Subcommand)]
    26→enum Commands {
    27→    /// Pre-commit size validation
    28→    Guard(GuardArgs),
    29→
    30→    /// Atomic commit with lock, stage, guard, and optional claude message
    31→    #[command(name = "vvx_commit")]
    32→    VvxCommit(CommitArgs),
    33→
    34→    /// Create invitatory commit to open new officium
    35→    #[command(name = "vvx_invitatory")]
    36→    VvxInvitatory,
    37→
    38→    /// Push with lock (prevents concurrent push/commit)
    39→    #[command(name = "vvx_push")]
    40→    VvxPush(PushArgs),
    41→
    42→    /// Force-break a stuck lock (use after crash)
    43→    #[command(name = "vvx_unlock")]
    44→    VvxUnlock,
    45→
    46→    /// Collect kit assets to staging directory
    47→    #[command(name = "release_collect")]
    48→    ReleaseCollect(ReleaseCollectArgs),
    49→
    50→    /// Brand staging directory with hallmark
    51→    #[command(name = "release_brand")]
    52→    ReleaseBrand(ReleaseBrandArgs),
    53→
    54→    /// Install kit assets from parcel to target repo
    55→    #[command(name = "vvx_emplace")]
    56→    VvxEmplace(EmplaceArgs),
    57→
    58→    /// Remove kit assets from target repo
    59→    #[command(name = "vvx_vacate")]
    60→    VvxVacate(VacateArgs),
    61→
    62→    /// Freshen CLAUDE.md managed sections from kit forge templates
    63→    #[command(name = "vvx_freshen")]
    64→    VvxFreshen(FreshenArgs),
    65→
    66→    /// External subcommands (delegated to kit CLIs)
    67→    #[command(external_subcommand)]
    68→    External(Vec<OsString>),
    69→}
    70→
    71→/// Arguments for guard command (wraps vvc)
    72→#[derive(clap::Args, Debug)]
    73→struct GuardArgs {
    74→    /// Size limit in bytes (default: 500000)
    75→    #[arg(long, default_value = "500000")]
    76→    limit: u64,
    77→
    78→    /// Warning threshold in bytes (default: 250000)
    79→    #[arg(long, default_value = "250000")]
    80→    warn: u64,
    81→}
    82→
    83→/// Arguments for vvx_commit command (wraps vvc)
    84→#[derive(clap::Args, Debug)]
    85→struct CommitArgs {
    86→    /// Prefix string to prepend to commit message
    87→    #[arg(long)]
    88→    prefix: Option<String>,
    89→
    90→    /// Commit message; if absent, invoke claude to generate from diff
    91→    #[arg(short, long)]
    92→    message: Option<String>,
    93→
    94→    /// Allow empty commits
    95→    #[arg(long)]
    96→    allow_empty: bool,
    97→
    98→    /// Skip 'git add -A' (respect pre-staged files)
    99→    #[arg(long)]
   100→    no_stage: bool,
   101→}
   102→
   103→/// Arguments for vvx_push command
   104→#[derive(clap::Args, Debug)]
   105→struct PushArgs {
   106→    /// Remote name (default: origin)
   107→    #[arg(long, default_value = "origin")]
   108→    remote: String,
   109→
   110→    /// Branch name (default: current branch)
   111→    #[arg(long)]
   112→    branch: Option<String>,
   113→
   114→    /// Force push (use with caution)
   115→    #[arg(long)]
   116→    force: bool,
   117→}
   118→
   119→/// Arguments for release_collect command
   120→#[derive(clap::Args, Debug)]
   121→struct ReleaseCollectArgs {
   122→    /// Staging directory to populate
   123→    #[arg(long)]
   124→    staging: PathBuf,
   125→
   126→    /// Source Tools/ directory
   127→    #[arg(long)]
   128→    tools_dir: PathBuf,
   129→
   130→    /// Path to vvi_install.sh
   131→    #[arg(long)]
   132→    install_script: PathBuf,
   133→
   134→    /// Comma-separated list of kit IDs (from BURC_MANAGED_KITS)
   135→    #[arg(long)]
   136→    managed_kits: String,
   137→}
   138→
   139→/// Arguments for release_brand command
   140→#[derive(clap::Args, Debug)]
   141→struct ReleaseBrandArgs {
   142→    /// Staging directory with collected assets
   143→    #[arg(long)]
   144→    staging: PathBuf,
   145→
   146→    /// Path to vovr_registry.json
   147→    #[arg(long)]
   148→    registry: PathBuf,
   149→
   150→    /// Current git commit SHA
   151→    #[arg(long)]
   152→    commit: String,
   153→
   154→    /// Comma-separated list of kit IDs (from BURC_MANAGED_KITS)
   155→    #[arg(long)]
   156→    managed_kits: String,
   157→}
   158→
   159→/// Arguments for vvx_emplace command
   160→#[derive(clap::Args, Debug)]
   161→struct EmplaceArgs {
   162→    /// Extracted parcel directory (contains vvbf_brand.json, kits/)
   163→    #[arg(long)]
   164→    parcel: PathBuf,
   165→
   166→    /// Path to target repo's burc.env file
   167→    #[arg(long)]
   168→    burc: PathBuf,
   169→}
   170→
   171→/// Arguments for vvx_vacate command
   172→#[derive(clap::Args, Debug)]
   173→struct VacateArgs {
   174→    /// Path to target repo's burc.env file
   175→    #[arg(long)]
   176→    burc: PathBuf,
   177→}
   178→
   179→/// Arguments for vvx_freshen command
   180→#[derive(clap::Args, Debug)]
   181→struct FreshenArgs {
   182→    /// Path to burc.env file (resolves project_root and tools_dir)
   183→    #[arg(long)]
   184→    burc: PathBuf,
   185→}
   186→
   187→/// Environment gate — panics if Claude Code environment is misconfigured.
   188→/// Called unconditionally before any argument parsing or library use.
   189→fn vosr_init() {
   190→    if std::env::var("CLAUDE_CODE_DISABLE_AUTO_MEMORY").as_deref() != Ok("1") {
   191→        panic!("CLAUDE_CODE_DISABLE_AUTO_MEMORY must be 1");
   192→    }
   193→}
   194→
   195→#[tokio::main]
   196→async fn main() -> ExitCode {
   197→    vosr_init();
   198→    let cli = Cli::parse();
   199→
   200→    let exit_code = match cli.command {
   201→        Some(Commands::Guard(args)) => run_guard(args),
   202→        Some(Commands::VvxCommit(args)) => run_commit(args),
   203→        Some(Commands::VvxInvitatory) => run_invitatory().await,
   204→        Some(Commands::VvxPush(args)) => run_push(args),
   205→        Some(Commands::VvxUnlock) => run_unlock(),
   206→        Some(Commands::ReleaseCollect(args)) => run_release_collect(args),
   207→        Some(Commands::ReleaseBrand(args)) => run_release_brand(args),
   208→        Some(Commands::VvxEmplace(args)) => run_emplace(args),
   209→        Some(Commands::VvxVacate(args)) => run_vacate(args),
   210→        Some(Commands::VvxFreshen(args)) => run_freshen(args),
   211→        Some(Commands::External(args)) => dispatch_external(args).await,
   212→        None => {
   213→            use clap::CommandFactory;
   214→            Cli::command().print_help().ok();
   215→            0
   216→        }
   217→    };
   218→
   219→    ExitCode::from(exit_code as u8)
   220→}
   221→
   222→/// Run guard command using vvc
   223→fn run_guard(args: GuardArgs) -> i32 {
   224→    let vvc_args = vvc::vvcg_GuardArgs {
   225→        limit: args.limit,
   226→        warn: args.warn,
   227→    };
   228→    vvc::guard(&vvc_args, None)
   229→}
   230→
   231→/// Run commit command using vvc
   232→fn run_commit(args: CommitArgs) -> i32 {
   233→    let vvc_args = vvc::vvcc_CommitArgs {
   234→        prefix: args.prefix,
   235→        message: args.message,
   236→        allow_empty: args.allow_empty,
   237→        no_stage: args.no_stage,
   238→        size_limit: vvc::VVCG_SIZE_LIMIT,
   239→        warn_limit: vvc::VVCG_WARN_LIMIT,
   240→    };
   241→    vvc::commit(&vvc_args)
   242→}
   243→
   244→/// Run invitatory command using vvc
   245→async fn run_invitatory() -> i32 {
   246→    match vvc::vvcp_invitatory().await {
   247→        Ok(()) => 0,
   248→        Err(e) => {
   249→            eprintln!("invitatory: error: {}", e);
   250→            1
   251→        }
   252→    }
   253→}
   254→
   255→/// Dispatch external subcommands to appropriate kit CLIs
   256→async fn dispatch_external(args: Vec<OsString>) -> i32 {
   257→    if args.is_empty() {
   258→        eprintln!("vvx: error: no subcommand provided");
   259→        return 1;
   260→    }
   261→
   262→    let cmd_name = args[0].to_string_lossy();
   263→
   264→    // Delegate to JJK if available and command matches
   265→    #[cfg(feature = "jjk")]
   266→    if jjk::jjrx_is_jjk_command(&cmd_name) {
   267→        return jjk::jjrx_dispatch(&args).await;
   268→    }
   269→
   270→    // Unknown external subcommand
   271→    eprintln!("vvx: error: unknown command '{}'", cmd_name);
   272→    eprintln!("Run 'vvx --help' for available commands");
   273→    1
   274→}
   275→
   276→/// Lock reference path for push operations (same as commit to prevent concurrent ops)
   277→const LOCK_REF: &str = "refs/vvg/locks/vvx";
   278→
   279→/// Force-break a stuck lock
   280→fn run_unlock() -> i32 {
   281→    use std::process::Command;
   282→
   283→    // Check if lock exists
   284→    let check = Command::new("git")
   285→        .args(["show-ref", "--verify", "--quiet", LOCK_REF])
   286→        .status();
   287→
   288→    match check {
   289→        Ok(status) if status.success() => {
   290→            // Lock exists, delete it
   291→            let delete = Command::new("git")
   292→                .args(["update-ref", "-d", LOCK_REF])
   293→                .output();
   294→
   295→            match delete {
   296→                Ok(output) if output.status.success() => {
   297→                    eprintln!("unlock: lock broken successfully");
   298→                    0
   299→                }
   300→                Ok(output) => {
   301→                    eprintln!("unlock: error: failed to delete lock: {}",
   302→                        String::from_utf8_lossy(&output.stderr));
   303→                    1
   304→                }
   305→                Err(e) => {
   306→                    eprintln!("unlock: error: {}", e);
   307→                    1
   308→                }
   309→            }
   310→        }
   311→        Ok(_) => {
   312→            // Lock doesn't exist
   313→            eprintln!("unlock: no lock held");
   314→            0
   315→        }
   316→        Err(e) => {
   317→            eprintln!("unlock: error checking lock: {}", e);
   318→            1
   319→        }
   320→    }
   321→}
   322→
   323→fn run_push(args: PushArgs) -> i32 {
   324→    use std::process::Command;
   325→
   326→    eprintln!("push: acquiring lock...");
   327→    let head_output = Command::new("git")
   328→        .args(["rev-parse", "HEAD"])
   329→        .output();
   330→
   331→    let lock_value = match head_output {
   332→        Ok(output) if output.status.success() => {
   333→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   334→        }
   335→        _ => "0000000000000000000000000000000000000000".to_string(),
   336→    };
   337→
   338→    let lock_result = Command::new("git")
   339→        .args(["update-ref", LOCK_REF, &lock_value, ""])
   340→        .output();
   341→
   342→    match lock_result {
   343→        Ok(output) if output.status.success() => {
   344→            // Lock acquired
   345→        }
   346→        _ => {
   347→            eprintln!("push: error: Another operation in progress - lock held");
   348→            return 1;
   349→        }
   350→    }
   351→
   352→    let result = run_push_workflow(&args);
   353→
   354→    let _ = Command::new("git")
   355→        .args(["update-ref", "-d", LOCK_REF])
   356→        .output();
   357→
   358→    match result {
   359→        Ok(()) => {
   360→            eprintln!("push: success");
   361→            0
   362→        }
   363→        Err(e) => {
   364→            eprintln!("push: error: {}", e);
   365→            1
   366→        }
   367→    }
   368→}
   369→
   370→fn run_push_workflow(args: &PushArgs) -> Result<(), String> {
   371→    use std::process::Command;
   372→
   373→    let branch = match &args.branch {
   374→        Some(b) => b.clone(),
   375→        None => {
   376→            let output = Command::new("git")
   377→                .args(["rev-parse", "--abbrev-ref", "HEAD"])
   378→                .output()
   379→                .map_err(|e| format!("Failed to get current branch: {}", e))?;
   380→
   381→            if !output.status.success() {
   382→                return Err("Failed to determine current branch".to_string());
   383→            }
   384→
   385→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   386→        }
   387→    };
   388→
   389→    eprintln!("push: pushing {} to {}", branch, args.remote);
   390→
   391→    let mut push_args = vec!["push", &args.remote, &branch];
   392→    if args.force {
   393→        push_args.push("--force");
   394→    }
   395→
   396→    let output = Command::new("git")
   397→        .args(&push_args)
   398→        .output()
   399→        .map_err(|e| format!("Failed to run git push: {}", e))?;
   400→
   401→    if !output.status.success() {
   402→        let stderr = String::from_utf8_lossy(&output.stderr);
   403→        return Err(format!("git push failed: {}", stderr));
   404→    }
   405→
   406→    Ok(())
   407→}
   408→
   409→/// Run release_collect command
   410→fn run_release_collect(args: ReleaseCollectArgs) -> i32 {
   411→    eprintln!("release_collect: collecting assets...");
   412→    eprintln!("  staging: {}", args.staging.display());
   413→    eprintln!("  tools_dir: {}", args.tools_dir.display());
   414→    eprintln!("  install_script: {}", args.install_script.display());
   415→
   416→    // Parse comma-separated kit list
   417→    let managed_kits: Vec<String> = args.managed_kits
   418→        .split(',')
   419→        .map(|s| s.trim().to_string())
   420→        .filter(|s| !s.is_empty())
   421→        .collect();
   422→
   423→    match vof::vofr_collect(&args.tools_dir, &args.staging, &args.install_script, &managed_kits) {
   424→        Ok(result) => {
   425→            // Output JSON for bash to parse
   426→            let mut output = serde_json::Map::new();
   427→            output.insert("total_files".to_string(), serde_json::Value::Number(result.total_files.into()));
   428→            output.insert("commands_routed".to_string(), serde_json::Value::Number(result.commands_routed.into()));
   429→
   430→            let kit_counts: serde_json::Map<String, serde_json::Value> = result.kit_counts
   431→                .into_iter()
   432→                .map(|(k, v)| (k, serde_json::Value::Number(v.into())))
   433→                .collect();
   434→            output.insert("kit_counts".to_string(), serde_json::Value::Object(kit_counts));
   435→
   436→            println!("{}", serde_json::to_string_pretty(&serde_json::Value::Object(output)).unwrap());
   437→            eprintln!("release_collect: success - {} files collected", result.total_files);
   438→            0
   439→        }
